public int[] shiftLeft(int[] nums) {
    int[] newNums = new int[nums.length];

    for (int i = 0; i < nums.length - 1; i++) {
        newNums[i] = nums[i + 1];
    }
    newNums[nums.length - 1] = nums[0];

    return newNums;
}

